using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class NotificationsTraining : TrainingContentBase
{
    public NotificationsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Overview",
            Slug = "notifications-overview",
            Summary = "What notifications are, how real-time push works, notification types, severity levels, and email delivery.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","real-time","signalr"]""",
            ContentJson = """{"body":"## Notifications Overview\n\nThe Notifications system keeps you informed of important events across QB Engineer in real time. Notifications are delivered instantly via SignalR push and optionally by email, ensuring you never miss a critical update — whether you're at your desk or away from the application.\n\n### How Real-Time Push Works\n\nWhen an event occurs (a job is assigned to you, an expense is overdue, a teammate mentions you), the server creates a notification and pushes it to your browser instantly via SignalR WebSocket. You see the bell icon badge update in the header without refreshing. If your connection drops temporarily, the system catches up when the panel reopens by reloading from the API.\n\n### Notification Types\n\nNotifications are categorized by what triggered them:\n- **Assignment** — a job, task, or responsibility was assigned to you\n- **Overdue** — a job, task, or deadline has passed its due date\n- **Expense** — an expense requires your approval or was approved/rejected\n- **Maintenance** — an asset status changed or maintenance is due\n- **System** — application-level events (sync completed, backup finished, scheduled task ran)\n- **Message** — a direct message or chat room message was sent to you\n- **Mention** — someone @mentioned you in a comment or activity log\n\n### Severity Levels\n\nEach notification carries a severity that controls its visual presentation and email behavior:\n- **Info** (blue) — informational updates that don't require immediate action. Examples: job moved to next stage, expense approved, sync completed.\n- **Warning** (yellow) — something needs attention soon. Examples: job approaching due date, asset nearing tool life expectancy, expense pending approval for 3+ days.\n- **Critical** (red) — requires immediate attention. Examples: job overdue, system error, asset out of service, failed sync.\n\n### Email Delivery\n\nNotifications can be delivered by email in addition to the in-app push. Email delivery is controlled per category in your notification preferences:\n- **Critical notifications** — email enabled by default (recommended to leave on)\n- **Assignment notifications** — email enabled by default\n- **Mention notifications** — email enabled by default\n\nEmails are sent via SMTP and include a direct link back to the relevant entity in QB Engineer. You can enable or disable each email category independently on the Notifications page under the Preferences tab.\n\n### The Bell Icon\n\nThe notification bell in the application header shows a badge with your unread count. Clicking it opens the notification panel — a slide-out overlay with tabs for All, Messages, and Alerts. Dismissed notifications are hidden from the panel but preserved in the system for audit purposes.\n\n### Sound Notifications\n\nA subtle audio alert can play when a new notification arrives. This is enabled by default and can be toggled off in Preferences. Sound is especially useful on shop floor displays where you might not be watching the screen constantly.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications — Guided Tour",
            Slug = "notifications-walkthrough",
            Summary = "A guided tour of the notification bell, panel, tabs, actions, and preferences.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Tour Notifications","steps":[{"element":".app-header__actions","popover":{"title":"Header Actions","description":"The notification bell, chat, and other controls are in the header actions area. The bell icon shows a red badge with your unread count. Click it to open the notification panel, which slides out with tabs for All, Messages, and Alerts.","side":"bottom"}},{"element":".user-trigger","popover":{"title":"User Menu","description":"Access your profile, account settings, and notification preferences from the user menu. Notification preferences let you control email delivery per category and toggle sound alerts.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Field Reference",
            Slug = "notifications-field-reference",
            Summary = "Complete reference for notification fields, severity levels, types, panel controls, preferences, actions, and filtering.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","reference"]""",
            ContentJson = """{"title":"Notifications Field Reference","groups":[{"heading":"Notification Fields","items":[{"label":"Title","value":"Short summary of the notification event. Displayed in bold when unread. Examples: 'Job #1042 assigned to you', 'Expense approved'."},{"label":"Message","value":"Detailed description of the notification event. Provides context beyond the title. Examples: 'Hartman, Daniel J assigned Job #1042 — CNC Bracket Assembly to you', 'Your $245.00 travel expense was approved by Smith, Jane A'."},{"label":"Type","value":"Categorizes what triggered the notification. Values: assignment, overdue, expense, maintenance, system, message, mention. Used for filtering and routing."},{"label":"Severity","value":"Visual priority level. Values: info (blue — informational), warning (yellow — needs attention), critical (red — immediate action required). Controls left border color and email delivery defaults."},{"label":"Source","value":"Where the notification originated. Values: user (from another person — messages, mentions, assignments) or system (automated — overdue alerts, sync events, maintenance warnings)."},{"label":"Is Read","value":"Boolean flag. Unread notifications show bold title text and contribute to the bell badge count. Marking as read removes the bold styling and decrements the badge."},{"label":"Is Pinned","value":"Boolean flag. Pinned notifications always sort to the top of the list regardless of date. Useful for keeping important items visible. Toggle on/off per notification."},{"label":"Is Dismissed","value":"Boolean flag. Dismissed notifications are hidden from the panel but preserved in the database. They do not appear in any tab or filter view. Cannot be undone from the panel."},{"label":"Entity Type","value":"Optional. The type of entity this notification relates to (e.g., job, expense, asset, part). Enables click-to-navigate from the notification to the source entity."},{"label":"Entity ID","value":"Optional. The ID of the related entity. Combined with Entity Type, creates a navigable link in the notification panel."},{"label":"Sender Initials","value":"Optional. Two-letter initials of the user who triggered the notification (for user-sourced notifications). Displayed in the avatar circle."},{"label":"Sender Color","value":"Optional. Background color of the sender's avatar circle. Matches the user's assigned color in the system."},{"label":"Created At","value":"Timestamp when the notification was created. Displayed as relative time in the panel (e.g., '5 min ago', '2 hours ago') and as MM/dd/yyyy hh:mm in the full notifications table."}]},{"heading":"Severity Levels","items":[{"label":"Info (blue border)","value":"Informational updates. No immediate action needed. Examples: job moved to next stage, expense approved, file uploaded, sync completed. Default email: OFF."},{"label":"Warning (yellow border)","value":"Attention needed soon. Examples: job approaching due date, asset nearing tool life, pending expense approval for 3+ days. Default email: OFF."},{"label":"Critical (red border)","value":"Immediate attention required. Examples: job overdue, system error, asset out of service, failed integration sync, security alert. Default email: ON."}]},{"heading":"Notification Types","items":[{"label":"Assignment","value":"Triggered when a job, task, or responsibility is assigned to the user. Source: user. Default email: ON."},{"label":"Overdue","value":"Triggered when a job, task, or deadline passes its due date. Source: system. Severity is typically warning or critical."},{"label":"Expense","value":"Triggered for expense approval requests, approvals, and rejections. Source: system or user depending on the action."},{"label":"Maintenance","value":"Triggered when an asset's status changes to Maintenance or Out of Service, or when scheduled maintenance is due. Source: system."},{"label":"System","value":"Application-level events: backup completion, sync status, scheduled task results, configuration changes. Source: system."},{"label":"Message","value":"Triggered when a direct message or chat room message is received. Source: user. Shows sender avatar."},{"label":"Mention","value":"Triggered when another user @mentions you in a comment, activity log, or chat message. Source: user. Default email: ON."}]},{"heading":"Panel Tabs","items":[{"label":"All","value":"Shows every non-dismissed notification regardless of source. Default tab when the panel opens."},{"label":"Messages","value":"Filters to user-sourced notifications only. Shows DMs, chat messages, mentions, and assignment notifications from other users."},{"label":"Alerts","value":"Filters to system-sourced notifications only. Shows overdue warnings, maintenance alerts, sync events, and automated system notifications."}]},{"heading":"Panel Actions","items":[{"label":"Mark as Read (per item)","value":"Click a notification to mark it as read. Bold title becomes normal weight. Unread badge decrements by one. Optimistic UI — updates locally, syncs to server."},{"label":"Pin / Unpin (per item)","value":"Toggle pin on a notification to keep it at the top of the list. Pinned items sort before unpinned regardless of date. Useful for tracking ongoing issues."},{"label":"Dismiss (per item)","value":"Hide a single notification from the panel. The notification is flagged as dismissed and excluded from all views. Preserved in the database for audit."},{"label":"Mark All Read (bulk)","value":"Marks every notification as read in one action. Badge count drops to zero. Affects all notifications, not just the current tab filter."},{"label":"Dismiss All (bulk)","value":"Dismisses every visible notification. Clears the panel. Dismissed items are hidden but preserved."}]},{"heading":"Notification Preferences","items":[{"label":"Email on Critical","value":"Toggle. When ON, critical-severity notifications are also sent via SMTP email. Default: ON. Found on Notifications page → Preferences tab."},{"label":"Email on Assignment","value":"Toggle. When ON, assignment notifications are sent via email. Default: ON. Useful for staying informed when away from the app."},{"label":"Email on Mention","value":"Toggle. When ON, @mention notifications are sent via email. Default: ON. Ensures you see mentions even when not actively using QB Engineer."},{"label":"Sound Enabled","value":"Toggle. When ON, plays an audio alert when a new notification arrives via SignalR. Default: ON. Can be turned off for quiet environments."}]},{"heading":"Filtering (Notifications Page)","items":[{"label":"Search","value":"Text filter across notification title and message fields. Filters in real time as you type."},{"label":"Severity Filter","value":"Dropdown: All, Info, Warning, Critical. Filters the table to show only notifications of the selected severity."},{"label":"Source Filter","value":"Dropdown: All, System, Board, Timer. Filters by the notification source."}]},{"heading":"Table Columns (Notifications Page)","items":[{"label":"Title","value":"Sortable. The notification's short summary text."},{"label":"Message","value":"Sortable. The detailed notification message."},{"label":"Severity","value":"Sortable, filterable (enum). Color-coded: info, warning, critical."},{"label":"Source","value":"Sortable. Whether the notification came from a user or the system."},{"label":"Date","value":"Sortable, date type. When the notification was created. Width: 150px."}]},{"heading":"SignalR Real-Time","items":[{"label":"Hub endpoint","value":"/hubs/notifications — WebSocket connection authenticated via JWT query string parameter."},{"label":"Event: notificationReceived","value":"Pushed from server when a new notification is created. The client's NotificationHubService receives it and calls NotificationService.push() to add it to the in-memory list."},{"label":"Connection recovery","value":"When the panel opens, it reloads notifications from the API to catch any missed during disconnection. The connection banner shows yellow for reconnecting, red for disconnected."},{"label":"Auto-connect","value":"NotificationHub connects automatically on app init (after authentication) in AppComponent.ngOnInit(). No manual setup needed per page."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Notifications Knowledge Check",
            Slug = "notifications-quiz",
            Summary = "Test your knowledge of the notification system: types, severity, panel actions, preferences, and real-time delivery.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/dashboard"]""",
            Tags = """["notifications","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"notif1","text":"You see a red badge with the number 3 on the bell icon in the header. What does this mean?","options":[{"id":"a","text":"There are 3 critical-severity notifications waiting"},{"id":"b","text":"There are 3 unread, non-dismissed notifications across all types and severities","isCorrect":true},{"id":"c","text":"There are 3 new notifications that arrived in the last hour"},{"id":"d","text":"There are 3 pinned notifications in your panel"}],"explanation":"The bell badge shows the count of all unread, non-dismissed notifications regardless of type or severity. It updates in real time via SignalR as new notifications arrive or existing ones are marked read."},{"id":"notif2","text":"You want to see only system-generated alerts (overdue warnings, sync events) and hide messages from other users. Which panel tab do you select?","options":[{"id":"a","text":"All — then manually scan for system notifications"},{"id":"b","text":"Messages — system alerts are classified as messages"},{"id":"c","text":"Alerts — this tab filters to system-sourced notifications only","isCorrect":true},{"id":"d","text":"There is no way to filter by source in the panel"}],"explanation":"The Alerts tab filters to system-sourced notifications only. The Messages tab shows user-sourced notifications (DMs, mentions, assignments from people). The All tab shows everything."},{"id":"notif3","text":"A notification has a yellow left border in the panel. What severity level does this indicate?","options":[{"id":"a","text":"Info — general informational update"},{"id":"b","text":"Warning — something needs attention soon","isCorrect":true},{"id":"c","text":"Critical — immediate action required"},{"id":"d","text":"Pinned — the notification has been pinned to the top"}],"explanation":"Yellow border indicates Warning severity — something needs your attention soon but is not yet critical. Blue is Info (informational), Red is Critical (immediate action). Border color is not related to pin status."},{"id":"notif4","text":"You dismiss all notifications using the Dismiss All button. Can these notifications be recovered?","options":[{"id":"a","text":"No — dismissed notifications are permanently deleted from the system"},{"id":"b","text":"Yes — dismissed notifications are hidden from the panel but preserved in the database for audit purposes","isCorrect":true},{"id":"c","text":"Only if you undo within 10 seconds using the snackbar action"},{"id":"d","text":"Only admins can recover dismissed notifications from the trash"}],"explanation":"Dismissed notifications are flagged as dismissed and hidden from the panel, but they are never deleted. The data is preserved in the database for audit and compliance purposes. However, there is no UI to un-dismiss from the panel."},{"id":"notif5","text":"You want an important notification to stay at the top of your panel regardless of when it was created. How do you accomplish this?","options":[{"id":"a","text":"Mark it as critical severity to force it to the top"},{"id":"b","text":"Pin the notification — pinned items always sort above unpinned ones","isCorrect":true},{"id":"c","text":"Star the notification using the star icon"},{"id":"d","text":"Move it to the Messages tab where it will be prioritized"}],"explanation":"Pinning a notification keeps it at the top of the list. Pinned notifications sort before all unpinned notifications regardless of their creation date. You can toggle pin on and off for any notification."},{"id":"notif6","text":"Which notification preference is enabled by default to ensure you receive emails for the most urgent events?","options":[{"id":"a","text":"Email on all notifications regardless of severity"},{"id":"b","text":"Email on Critical notifications","isCorrect":true},{"id":"c","text":"Email on Warning and Critical notifications"},{"id":"d","text":"No email preferences are enabled by default"}],"explanation":"Email on Critical is enabled by default because critical notifications indicate events requiring immediate attention (overdue jobs, system errors, asset failures). Email on Assignment and Email on Mention are also ON by default. General info and warning notifications do not trigger emails by default."},{"id":"notif7","text":"You are working on the shop floor and not looking at the screen. How does QB Engineer alert you when a new notification arrives?","options":[{"id":"a","text":"The screen flashes red for critical notifications"},{"id":"b","text":"An audio alert plays when a notification arrives via SignalR, if the Sound Enabled preference is on","isCorrect":true},{"id":"c","text":"The application sends an SMS to your registered phone number"},{"id":"d","text":"There is no way to receive alerts without watching the screen"}],"explanation":"When Sound Enabled is toggled ON in notification preferences (the default), an audio alert plays each time a new notification is pushed via SignalR. This is especially useful on shop floor kiosk displays. You can disable it in the Preferences tab if you prefer a quiet environment."},{"id":"notif8","text":"Your browser lost its WebSocket connection to the server for 2 minutes. When the connection recovers, how does QB Engineer ensure you haven't missed any notifications?","options":[{"id":"a","text":"The SignalR client automatically replays all missed events from a server-side buffer"},{"id":"b","text":"When the notification panel opens, it reloads the full notification list from the API to catch any missed during disconnection","isCorrect":true},{"id":"c","text":"Missed notifications are permanently lost and must be checked via email"},{"id":"d","text":"The system sends a batch email with all missed notifications after reconnection"}],"explanation":"Every time the notification panel opens, it makes a fresh API call to reload notifications. This catches any notifications that were created while the WebSocket was disconnected. The connection banner also shows a visual indicator (yellow for reconnecting, red for disconnected) so you know the real-time feed is interrupted."},{"id":"notif9","text":"A colleague @mentions you in a job's activity log comment. What type and source will the resulting notification have?","options":[{"id":"a","text":"Type: mention, Source: user","isCorrect":true},{"id":"b","text":"Type: message, Source: system"},{"id":"c","text":"Type: assignment, Source: user"},{"id":"d","text":"Type: system, Source: user"}],"explanation":"An @mention from another user creates a notification with type 'mention' and source 'user'. This means it appears under the Messages tab (user-sourced), and if your Email on Mention preference is enabled, you'll also receive an email."},{"id":"notif10","text":"You click Mark All Read in the notification panel. Which of the following is true?","options":[{"id":"a","text":"Only notifications in the currently selected tab are marked as read"},{"id":"b","text":"All notifications are marked as read, the badge count drops to zero, and the change syncs to the server in the background","isCorrect":true},{"id":"c","text":"All notifications are dismissed and removed from the panel"},{"id":"d","text":"Only unread notifications from the last 24 hours are marked as read"}],"explanation":"Mark All Read is a bulk action that marks every notification as read (not just those in the current tab). The bell badge count drops to zero immediately via optimistic UI, and the change is persisted to the server via an API call in the background. Notifications remain visible in the panel — they are not dismissed."}]}"""
        });

        Log.Information("Seeded Notifications training modules");
    }
}
